/**
 * @name Taint from HTTP request to response output (Reflected XSS)
 * @description Tracks user-controlled input flowing directly to HTTP response output without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/reflected-xss-keycloak
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module XssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // PrintWriter write/println
    exists(MethodCall mc |
      (mc.getMethod().hasName("write") or mc.getMethod().hasName("println") or mc.getMethod().hasName("print")) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Response entity / output stream
    exists(MethodCall mc |
      mc.getMethod().hasName("entity") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.ws.rs.core", "Response$ResponseBuilder") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // OutputStream write
    exists(MethodCall mc |
      mc.getMethod().hasName("write") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "OutputStream") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module XssFlow = TaintTracking::Global<XssConfig>;
import XssFlow::PathGraph

from XssFlow::PathNode source, XssFlow::PathNode sink
where XssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS: user input flows to HTTP response output from $@.", source.getNode(), "user-controlled source"

/**
 * @name XSS via KeycloakSanitizerMethod - HTML sanitization bypass
 * @description Analyzes how the KeycloakSanitizer works and if user input can bypass it
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-sanitizer-bypass-keycloak
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Check if the OWASP HTML sanitizer is used and whether it provides safe output
class KeycloakSanitizerCall extends MethodCall {
  KeycloakSanitizerCall() {
    this.getMethod().getName() = "sanitize" and
    this.getMethod().getDeclaringType().hasQualifiedName("org.keycloak.theme", "KeycloakSanitizerMethod")
  }
}

module XssSanitizerConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Sinks: any output writing to a response in the services directory
    exists(MethodCall mc |
      (mc.getMethod().hasName("write") or mc.getMethod().hasName("println") or 
       mc.getMethod().hasName("print") or mc.getMethod().hasName("entity")) and
      sink.asExpr() = mc.getAnArgument() and
      mc.getFile().getRelativePath().matches("services/%")
    )
  }

  // Consider sanitize() calls as barriers
  predicate isBarrier(DataFlow::Node node) {
    exists(KeycloakSanitizerCall ksc | node.asExpr() = ksc)
  }
}

module XssSanitizerFlow = TaintTracking::Global<XssSanitizerConfig>;
import XssSanitizerFlow::PathGraph

from XssSanitizerFlow::PathNode source, XssSanitizerFlow::PathNode sink
where XssSanitizerFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS in service: unsanitized user input flows to response from $@.", source.getNode(), "user-controlled source"

/**
 * @name XSS in WelcomeResource and Admin setup pages
 * @description Checks if user-controlled input (like admin username/password from request) 
 *              flows into HTML response in the welcome/admin setup pages
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-welcome-resource
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module WelcomeXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Direct response.entity() with HTML/string content
    exists(MethodCall mc |
      mc.getMethod().hasName("entity") and
      sink.asExpr() = mc.getArgument(0) and
      (
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.services.resources", "WelcomeResource") or
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.quarkus.runtime.services.resources", "QuarkusWelcomeResource")
      )
    )
    or
    // String concatenation building HTML in welcome resource
    exists(MethodCall mc |
      (mc.getMethod().hasName("ok") or mc.getMethod().hasName("status")) and
      sink.asExpr() = mc.getAnArgument() and
      (
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.services.resources", "WelcomeResource") or
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.quarkus.runtime.services.resources", "QuarkusWelcomeResource")
      )
    )
  }
}

module WelcomeXssFlow = TaintTracking::Global<WelcomeXssConfig>;
import WelcomeXssFlow::PathGraph

from WelcomeXssFlow::PathNode source, WelcomeXssFlow::PathNode sink
where WelcomeXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS in WelcomeResource: user input flows to HTML response from $@.", source.getNode(), "user-controlled source"

/**
 * @name Admin username/password reflected in WelcomeResource HTML (XSS)
 * @description Checks if user-submitted username or password from POST form flows into HTML response unencoded
 * @kind path-problem
 * @problem.severity error
 * @id java/welcome-resource-admin-xss
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Sources: Form parameters in WelcomeResource methods
class WelcomeResourceFormParam extends DataFlow::Node {
  WelcomeResourceFormParam() {
    exists(Parameter p |
      p = this.asParameter() and
      p.getCallable().getDeclaringType().hasQualifiedName("org.keycloak.services.resources", "WelcomeResource") and
      p.getAnAnnotation().getType().hasName("FormParam")
    )
    or
    exists(Parameter p |
      p = this.asParameter() and
      p.getCallable().getDeclaringType().hasQualifiedName("org.keycloak.quarkus.runtime.services.resources", "QuarkusWelcomeResource") and
      p.getAnAnnotation().getType().hasName("FormParam")
    )
  }
}

module WelcomeAdminXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof WelcomeResourceFormParam or
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("entity") or mc.getMethod().hasName("ok")) and
      sink.asExpr() = mc.getAnArgument() and
      (
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.services.resources", "WelcomeResource") or
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.quarkus.runtime.services.resources", "QuarkusWelcomeResource")
      )
    )
  }
}

module WelcomeAdminXssFlow = TaintTracking::Global<WelcomeAdminXssConfig>;
import WelcomeAdminXssFlow::PathGraph

from WelcomeAdminXssFlow::PathNode source, WelcomeAdminXssFlow::PathNode sink
where WelcomeAdminXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Admin credential XSS in WelcomeResource: user form input '$@' flows unencoded to HTML response.", source.getNode(), "form parameter"

/**
