/**
 * @name User-controlled data embedded in JavaScript context without JS encoding
 * @description Detects user-controlled data from HTTP requests embedded in JavaScript strings
 * @kind path-problem
 * @problem.severity error
 * @id java/js-injection-keycloak
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Check specifically for data embedded into JS script blocks
class JsScriptSink extends DataFlow::Node {
  JsScriptSink() {
    // String concatenation where the result contains JS-like content
    exists(StringLiteral sl, AddExpr add |
      (sl.getValue().matches("%<script%") or
       sl.getValue().matches("%history.replaceState%") or
       sl.getValue().matches("%history.pushState%") or
       sl.getValue().matches("%window.location%") or
       sl.getValue().matches("% = '%") or
       sl.getValue().matches("% = \"%")) and
      add.getAChildExpr() = sl and
      this.asExpr() = add
    )
  }
}

module JsInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    sink instanceof JsScriptSink
    or
    // Writes with JS context (variable assignment in response)
    exists(MethodCall mc |
      (mc.getMethod().hasName("write") or mc.getMethod().hasName("println")) and
      sink.asExpr() = mc.getAnArgument() and
      exists(StringLiteral sl |
        DataFlow::localFlow(DataFlow::exprNode(sl), sink) and
        (sl.getValue().matches("%script%") or sl.getValue().matches("%replaceState%"))
      )
    )
  }
}

module JsInjectionFlow = TaintTracking::Global<JsInjectionConfig>;
import JsInjectionFlow::PathGraph

from JsInjectionFlow::PathNode source, JsInjectionFlow::PathNode sink
where JsInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "JavaScript context injection: user input from $@ embedded in JS.", source.getNode(), "user-controlled source"

/**
 * @name SAML RelayState HTML injection in POST binding form
 * @description SAML RelayState or SAMLResponse embedded in HTML form value attribute without HtmlUtils.escapeAttribute
 * @kind path-problem
 * @problem.severity error
 * @id java/saml-relaystate-html-injection
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

// Check HtmlUtils.escapeAttribute as a barrier
class HtmlEscapeBarrier extends DataFlow::Node {
  HtmlEscapeBarrier() {
    exists(MethodCall mc |
      mc.getMethod().getName().matches("%escape%") and
      mc.getMethod().getName().matches("%ttribute%") and
      this.asExpr() = mc
    )
    or
    exists(MethodCall mc |
      mc.getMethod().getDeclaringType().hasQualifiedName("org.keycloak.common.util", "HtmlUtils") and
      this.asExpr() = mc
    )
  }
}

module SAMLPostXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // SAML data from HTTP request
    exists(MethodCall mc |
      (mc.getMethod().hasName("getRelayState") or 
       mc.getMethod().hasName("getSAMLResponse") or
       mc.getMethod().hasName("getSamlResponse") or
       mc.getMethod().hasName("getQueryParamValue")) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // String concatenation building HTML in BaseSAML2BindingBuilder
    exists(AddExpr add |
      add.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.saml", "BaseSAML2BindingBuilder") and
      sink.asExpr() = add
    )
    or
    exists(MethodCall mc |
      mc.getMethod().hasName("entity") and
      (
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.saml", "BaseSAML2BindingBuilder") or
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.protocol.saml", "JaxrsSAML2BindingBuilder")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    node instanceof HtmlEscapeBarrier
  }
}

module SAMLPostXssFlow = TaintTracking::Global<SAMLPostXssConfig>;
import SAMLPostXssFlow::PathGraph

from SAMLPostXssFlow::PathNode source, SAMLPostXssFlow::PathNode sink
where SAMLPostXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "SAML HTML form injection: $@ flows unencoded into HTML POST form.", source.getNode(), "SAML data source"

/**
 * @name Error messages reflected in HTML responses 
 * @description Error messages containing user input or request data reflected in HTML responses without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/error-message-xss
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ErrorXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Sinks: response entity in error handlers, error pages, and admin/account console
    exists(MethodCall mc |
      mc.getMethod().hasName("entity") and
      sink.asExpr() = mc.getAnArgument() and
      (
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.services.error", "KeycloakErrorHandler") or
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.services.resources.admin", "AdminConsole") or
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.services.resources.account", "AccountConsole") or
        mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.services.resources", "RealmsResource")
      )
    )
  }
}

module ErrorXssFlow = TaintTracking::Global<ErrorXssConfig>;
import ErrorXssFlow::PathGraph

from ErrorXssFlow::PathNode source, ErrorXssFlow::PathNode sink
where ErrorXssFlow::flowPath(source, sink)
