/**
 * @name AdvancedMessageFormatterMethod HTML injection 
 * @description The AdvancedMessageFormatterMethod allows HTML in messages - check if user-controlled data flows into it without sanitization
 * @kind path-problem
 * @problem.severity error
 * @id java/advanced-message-formatter-xss
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module AdvancedMsgConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // FreeMarker template rendering with user-supplied data
    exists(MethodCall mc |
      mc.getMethod().hasName("processTemplate") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.keycloak.theme.freemarker", "DefaultFreeMarkerProvider") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // LoginFormsProvider.createResponse() with form attributes that include user data
    exists(MethodCall mc |
      (mc.getMethod().hasName("setAttribute") or mc.getMethod().hasName("setError") or mc.getMethod().hasName("setSuccess")) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.keycloak.forms.login.freemarker", "FreeMarkerLoginFormsProvider") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // FreeMarker template form attribute for login forms
    exists(MethodCall mc |
      mc.getMethod().hasName("setAttribute") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.forms.login.freemarker", "FreeMarkerLoginFormsProvider") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module AdvancedMsgFlow = TaintTracking::Global<AdvancedMsgConfig>;
import AdvancedMsgFlow::PathGraph

from AdvancedMsgFlow::PathNode source, AdvancedMsgFlow::PathNode sink
where AdvancedMsgFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "FreeMarker template XSS: user input from $@ flows into template rendering without sanitization.", source.getNode(), "remote source"
